            for &vi in &sample_indices {
                let v = &storage.vectors[vi * DIM..(vi + 1) * DIM];
                let cidx = nearest_centroid(v, &centroids, nlist);
                counts[cidx] += 1;
                let base = cidx * DIM;
                for d in 0..DIM {
                    sums[base + d] += v[d];
                }
            }

            for c in 0..nlist {
                let base = c * DIM;
                let cnt = counts[c];
                if cnt > 0 {
                    let inv = 1.0f32 / (cnt as f32);
                    for d in 0..DIM {
                        centroids[base + d] = sums[base + d] * inv;
                    }
