        for c in 0..nlist {
            let src_idx = sample_indices[c % sample_size];
            let src = &storage.vectors[src_idx * DIM..(src_idx + 1) * DIM];
            centroids[c * DIM..(c + 1) * DIM].copy_from_slice(src);
        }

