        return;
    }

    let mut pos = *len;
    while pos > 0 && item.0 < probes[pos - 1].0 {
        pos -= 1;
    }

    if *len < max_len {
        for i in (pos..*len).rev() {
            probes[i + 1] = probes[i];
        }
        probes[pos] = item;
        *len += 1;
    } else {
        for i in (pos..(*len - 1)).rev() {
            probes[i + 1] = probes[i];
        }
        probes[pos] = item;
    }
}

#[inline]
fn candidates_to_results(best: Vec<Candidate>) -> Vec<SearchResult> {
    best.into_iter()
        .map(|x| SearchResult {
            id: x.id,
            distance: x.dist_sq.sqrt(),
        })
        .collect()
}
