use crate::api::SearchResult;
use crate::distance::l2_distance_squared;
use std::cmp::Ordering;
use std::collections::BinaryHeap;
use std::sync::RwLock;

const DIM: usize = 128;

struct Storage {
    ids: Vec<u64>,
    vectors: Vec<f32>, // flattened: len = ids.len() * DIM
}

pub struct VectorDB {
    inner: RwLock<Storage>,
}

#[derive(Debug, Clone, Copy)]
struct HeapItem {
    dist_sq: f64,
    id: u64,
}

impl PartialEq for HeapItem {
    fn eq(&self, other: &Self) -> bool {
        self.dist_sq == other.dist_sq && self.id == other.id
    }
}

impl Eq for HeapItem {}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        // Max-heap by distance (largest distance at the top)
        self.dist_sq
            .partial_cmp(&other.dist_sq)
            .unwrap_or(Ordering::Equal)
            .then_with(|| self.id.cmp(&other.id))
    }
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            inner: RwLock::new(Storage {
                ids: Vec::new(),
                vectors: Vec::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != DIM {
            return;
        }

        let mut guard = self.inner.write().unwrap();
        guard.ids.push(id);
        guard.vectors.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut guard = self.inner.write().unwrap();

        let mut valid_count = 0usize;
        for (_, v) in &vectors {
            if v.len() == DIM {
                valid_count += 1;
            }
        }

        guard.ids.reserve(valid_count);
        guard.vectors.reserve(valid_count * DIM);

        let mut inserted = 0usize;
        for (id, vector) in vectors {
            if vector.len() != DIM {
                continue;
            }
            guard.ids.push(id);
            guard.vectors.extend_from_slice(&vector);
            inserted += 1;
        }

        inserted
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if vector.len() != DIM || top_k == 0 {
            return Vec::new();
        }

        let k = top_k as usize;
        let guard = self.inner.read().unwrap();
        let n = guard.ids.len();
        if n == 0 {
            return Vec::new();
        }

        let mut heap = BinaryHeap::with_capacity(k.min(n));

        for (i, candidate) in guard.vectors.chunks_exact(DIM).enumerate() {
            let dist_sq = l2_distance_squared(vector, candidate);
            let item = HeapItem {
                dist_sq,
                id: guard.ids[i],
            };

            if heap.len() < k {
                heap.push(item);
            } else if let Some(worst) = heap.peek() {
                if item.dist_sq < worst.dist_sq {
                    heap.pop();
                    heap.push(item);
                }
            }
        }

        let mut results: Vec<SearchResult> = heap
            .into_iter()
            .map(|x| SearchResult {
                id: x.id,
                distance: x.dist_sq.sqrt(),
            })
            .collect();

        results.sort_by(|a, b| {
            a.distance
                .partial_cmp(&b.distance)
                .unwrap_or(Ordering::Equal)
        });

        results
    }
}

#[inline]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    l2_distance_squared(a, b).sqrt()
}

#[inline]
pub fn l2_distance_squared(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());

    #[cfg(target_arch = "x86_64")]
    {
        if a.len() == 128 && std::arch::is_x86_feature_detected!("avx512f") {
            // SAFETY: guarded by runtime feature detection and fixed length check.
            return unsafe { l2_distance_sq_128_avx512(a, b) };
        }
    }

    l2_distance_sq_scalar(a, b)
}

#[inline]
fn l2_distance_sq_scalar(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0f64;
    for i in 0..a.len() {
        let d = (a[i] - b[i]) as f64;
        sum += d * d;
    }
    sum
}

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_sq_128_avx512(a: &[f32], b: &[f32]) -> f64 {
    use std::arch::x86_64::*;

    let pa = a.as_ptr();
    let pb = b.as_ptr();

    let mut acc = _mm512_setzero_ps();

    macro_rules! step {
        ($offset:expr) => {{
            let va = _mm512_loadu_ps(pa.add($offset));
            let vb = _mm512_loadu_ps(pb.add($offset));
            let diff = _mm512_sub_ps(va, vb);
            acc = _mm512_fmadd_ps(diff, diff, acc);
        }};
    }

    step!(0);
    step!(16);
    step!(32);
    step!(48);
    step!(64);
    step!(80);
    step!(96);
    step!(112);

    _mm512_reduce_add_ps(acc) as f64
}

