            let v = &storage.vectors[i * DIM..(i + 1) * DIM];
            let cidx = nearest_centroid(v, &centroids, nlist);
            lists[cidx].push(i);
        }

        *self.index.write().unwrap() = Some(IvfIndex {
            centroids,
            lists,
