    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        if vector.len() != DIM || top_k == 0 {
            return Vec::new();
        }

        self.ensure_index();

        let storage = self.inner.read().unwrap();
        let n = storage.ids.len();
        if n == 0 {
