        .into_iter()
        .map(|x| SearchResult {
            id: x.id,
            distance: x.dist_sq.sqrt(),
        })
        .collect();

    results.sort_by(|a, b| {
        a.distance
            .partial_cmp(&b.distance)
            .unwrap_or(Ordering::Equal)
    });

